def binary_xor(a, b):
    a_bin = format(a, 'b')
    b_bin = format(b, 'b')
    max_len = max(len(a_bin), len(b_bin))
    a_bin, b_bin = a_bin.zfill(max_len), b_bin.zfill(max_len)
    return '0b' + ''.join('1' if (ca != cb) else '0' for ca, cb in zip(a_bin, b_bin))

